"""Tool name transformer for ctxcli.

Transforms MCP tool names into natural CLI command structures.
Uses both naming convention parsing and schema metadata.
"""

import re
from dataclasses import dataclass, field
from typing import Any


@dataclass
class TransformedCommand:
    """Represents a transformed CLI command from an MCP tool."""

    entity: str
    verb: str
    original_name: str
    description: str = ""
    input_schema: dict[str, Any] = field(default_factory=dict)

    # Parameters extracted from pattern
    filter_field: str | None = None  # For filter_by patterns (e.g., "email")

    def get_positional_args(self) -> list[str]:
        """Get positional arguments (required params that are IDs)."""
        required = set(self.input_schema.get("required", []))
        # ID-like parameters should be positional
        return [name for name in required if name == "id" or name.endswith("_id")]

    def get_flag_args(self) -> dict[str, dict[str, Any]]:
        """Get flag arguments (all other params)."""
        props = self.input_schema.get("properties", {})
        required = set(self.input_schema.get("required", []))
        positional = set(self.get_positional_args())

        flags = {}
        for name, schema in props.items():
            if name not in positional:
                flags[name] = {
                    "type": schema.get("type", "string"),
                    "description": schema.get("description", ""),
                    "required": name in required,
                    "default": schema.get("default"),
                }
        return flags


# Transformation patterns: (regex, verb, additional_fields)
PATTERNS = [
    # filter_{entity}_by_{field} → entity filter --by={field} --value=<value>
    (re.compile(r"^filter_(.+)_by_(.+)$"), "filter", ["by"]),
    # get_{entity}_by_id → entity get <id>
    (re.compile(r"^get_(.+)_by_id$"), "get", []),
    # search_{entity}_by_text → entity search --search-term=<text>
    (re.compile(r"^search_(.+)_by_text$"), "search", []),
    # find_{entity}_by_{field}_range → entity find --{field}-min=X --{field}-max=Y
    (re.compile(r"^find_(.+)_by_(.+)_range$"), "find", ["range_field"]),
]


def transform_tool_name(
    name: str,
    description: str = "",
    input_schema: dict[str, Any] | None = None,
) -> TransformedCommand:
    """Transform an MCP tool name into a CLI command structure.

    Args:
        name: MCP tool name (e.g., "filter_user_by_email")
        description: Tool description
        input_schema: Tool input schema

    Returns:
        TransformedCommand with entity, verb, and parameters
    """
    input_schema = input_schema or {}

    # Try each pattern
    for pattern, verb, _extra_fields in PATTERNS:
        match = pattern.match(name)
        if match:
            groups = match.groups()
            entity = groups[0]

            # For filter/find patterns, include the field in the verb
            # to avoid collisions (e.g., filter_customer_by_email and
            # filter_customer_by_city both mapping to "filter")
            effective_verb = verb
            filter_field = None
            if verb in ("filter", "find") and len(groups) > 1:
                field = groups[1]
                effective_verb = f"{verb}-by-{field.replace('_', '-')}"
                filter_field = field

            return TransformedCommand(
                entity=entity,
                verb=effective_verb,
                original_name=name,
                description=description,
                input_schema=input_schema,
                filter_field=filter_field,
            )

    # Best-effort fallback: try to extract verb and entity
    return _best_effort_transform(name, description, input_schema)


def _best_effort_transform(
    name: str,
    description: str,
    input_schema: dict[str, Any],
) -> TransformedCommand:
    """Best-effort transformation for non-standard tool names.

    Tries to extract a verb (first part) and entity (rest).
    E.g., "calculate_shipping" → entity="shipping", verb="calculate"
    """
    parts = name.split("_")

    if len(parts) >= 2:
        # Common verbs that typically come first
        common_verbs = {"get", "create", "update", "delete", "list", "search", "filter", "find", "calculate", "send", "bulk"}

        if parts[0] in common_verbs:
            verb = parts[0]
            entity = "_".join(parts[1:])
        else:
            # Assume last part is verb, rest is entity
            verb = parts[-1]
            entity = "_".join(parts[:-1])
    else:
        # Single word: use as both entity and verb
        verb = "run"
        entity = name

    return TransformedCommand(
        entity=entity,
        verb=verb,
        original_name=name,
        description=description,
        input_schema=input_schema,
    )


def group_commands_by_entity(
    commands: list[TransformedCommand],
) -> dict[str, list[TransformedCommand]]:
    """Group transformed commands by entity.

    Args:
        commands: List of transformed commands

    Returns:
        Dictionary mapping entity names to their commands
    """
    grouped: dict[str, list[TransformedCommand]] = {}
    for cmd in commands:
        if cmd.entity not in grouped:
            grouped[cmd.entity] = []
        grouped[cmd.entity].append(cmd)
    return grouped

